#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long ans1 = 5 * X;          // 5 packets of size 2
        long long ans2 = 3 * X + Y;      // 3 packets of size 2 + 1 packet of size 4
        long long ans3 = X + 2 * Y;      // 1 packet of size 2 + 2 packets of size 4
        long long ans = ans1;
        if (ans2 < ans) ans = ans2;
        if (ans3 < ans) ans = ans3;
        printf("%lld\n", ans);
    }
    return 0;
}

